<template>
  <div class="login">
    <div class="login_content">
      <form>
        <div class="user">
          <label 
            for="user_name"
            class="label_name"
          />
          <input 
            type="text" 
            id="user_name"
            class="user_name"
            placeholder="用户名"
            v-model.trim="userName"
          >
        </div>
        <div class="user">
          <label 
            for="user_password"
            class="label_password"
          />
          <input 
            type="password"
            id="user_password"
            class="user_password"
            placeholder="密码"
            v-model.trim="userPassword"
          >
        </div>
        <input 
          type="submit" 
          value="登陆"
          class="submit"
          @click="login"
        >
      </form>
    </div>
    <my-footer class="login_footer" />
  </div>
</template>
<script>
import myFooter from "../commen/components/footer.vue";
import Api from "../api/login/api.js";
export default {
    data (){
        return {
            userName:"",
            userPassword:""

        };

    },
    methods:{
        /**
         * 用户登陆
         */
        login (){
            this.axios.post(`${Api.login}`,{
                userName:this.userName,
                userPassword:this.userPassword

            }).then (response => {
                // 登陆成功
                if(response.code === 200){
                    localStorage.setItem("token",response.data.token);
                    this.$store.commit("setToken",response.data.token);
                    // 登陆成功后跳转
                    let redirect = decodeURIComponent(this.$route.query.redirect || "/");
                    
                    this.$router.replace({
                        path:redirect
                    });
                }

                return;
            }).catch(error => {
                console.log(error);
            });
            

        }

    },
    components:{
        myFooter
    }
    
};
</script>
<style lang="scss" scoped>
.login{
    
    .login_content{
        $border:1px solid rgb(210,210,210);
        background-color:rgb(238,238,238);
        width:300px;
        padding-bottom:70px;
        border:$border;
        margin:40px 0 0 800px;
        padding-left:20px;
        .user{
            $height:50px;
            height:$height;
            width:100%;
            line-height:$height;
            position:relative;
            font-size:17px;
            font-weight: 500;
             margin-top:20px;
             .label_name,.label_password{
                 padding-right:30px;
             }
            .user_name,.user_password{
                position:absolute;
                $height:30px;
                left:32px;
                top:10px;
                height:$height;
                line-height:$height;
                width:237px;
                border: $border;
                padding-left:1px;
            }
            .label_name{
                background:url(../images/user.png) -360px -93px no-repeat;

            }
            .label_password{
                 background:url(../images/user.png) -360px -134px no-repeat;

            }
        }
        .submit{
            $height:40px;
            width:273px;
            height:$height;
            line-height:$height;
            text-align:center;
            border:none;
            color:whitesmoke;
            font-weight:500;
            font-size:17px;
            background-color:#F69;
            margin-top:30px;
            outline:none;
            cursor: pointer;
            
        }

    }
    .login_footer{
      margin-top:223px;
      
    }
    
}

</style>


